using System.ComponentModel.DataAnnotations;

namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }

    [Required, StringLength(100)]
    public string Title { get; set; } = string.Empty;

    [Required]
    public string Category { get; set; } = string.Empty;

    [Required]
    public string Ingredients { get; set; } = string.Empty;

    [Required]
    public string Steps { get; set; } = string.Empty;

    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Ingredients = "Pizza dough, Tomato sauce, Fresh mozzarella, Basil, Olive oil", Steps = "1. Preheat oven to 475°F\n2. Roll out dough\n3. Spread sauce and add cheese\n4. Bake 10-12 minutes\n5. Top with fresh basil" },
        new Recipe { Id = 2, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken breast, Yogurt, Tomato puree, Cream, Garam masala, Cumin, Turmeric", Steps = "1. Marinate chicken in spiced yogurt\n2. Grill chicken pieces\n3. Simmer sauce with tomato and cream\n4. Combine chicken and sauce\n5. Serve with rice" },
        new Recipe { Id = 3, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground beef, Taco shells, Lettuce, Tomato, Cheese, Sour cream, Taco seasoning", Steps = "1. Brown beef with seasoning\n2. Warm taco shells\n3. Assemble with toppings\n4. Serve with salsa" },
        new Recipe { Id = 4, Title = "Spaghetti Carbonara", Category = "Italian", Ingredients = "Spaghetti, Pancetta, Eggs, Parmesan, Black pepper", Steps = "1. Cook pasta al dente\n2. Fry pancetta until crisp\n3. Mix eggs and cheese\n4. Toss hot pasta with pancetta\n5. Stir in egg mixture off heat" },
        new Recipe { Id = 5, Title = "Pad Thai", Category = "Asian", Ingredients = "Rice noodles, Shrimp, Tofu, Bean sprouts, Peanuts, Tamarind paste, Fish sauce", Steps = "1. Soak noodles\n2. Stir-fry shrimp and tofu\n3. Add noodles and sauce\n4. Toss with bean sprouts\n5. Garnish with peanuts and lime" },
        new Recipe { Id = 6, Title = "Chocolate Lava Cake", Category = "Desserts", Ingredients = "Dark chocolate, Butter, Eggs, Sugar, Flour", Steps = "1. Melt chocolate and butter\n2. Whisk eggs and sugar\n3. Fold in flour and chocolate\n4. Bake 12 minutes at 425°F\n5. Invert onto plate and serve immediately" },
    };

    private int _nextId = 7;
    private readonly Dictionary<(int recipeId, string visitorId), int> _ratings = new();

    public List<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();

    public List<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _nextId++;
        _recipes.Add(recipe);
    }

    public void RateRecipe(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is null || stars < 1 || stars > 5) return;

        var totalStars = recipe.AverageRating * recipe.RatingCount + stars;
        recipe.RatingCount++;
        recipe.AverageRating = totalStars / recipe.RatingCount;
    }
}

