@page "/category/{CategoryName}"
@using RecipeCommunity.Services
@using RecipeCommunity.Models

@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes</PageTitle>

<h1>@CategoryName Recipes</h1>
<a href="/" class="btn btn-outline-secondary mb-3">← Back to Categories</a>

@if (recipes.Any())
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="text-muted">
                            @if (recipe.RatingCount > 0)
                            {
                                <span>⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)</span>
                            }
                            else
                            {
                                <span>No ratings yet</span>
                            }
                        </p>
                        <a href="/recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}
else
{
    <p>No recipes found in this category.</p>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;

    private List<Recipe> recipes = new();

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeCommunity.Services
@using RecipeCommunity.Models
@using RecipeCommunity.Components.Shared

@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe")</PageTitle>

@if (recipe is null)
{
    <p>Recipe not found.</p>
}
else
{
    <a href="/category/@recipe.Category" class="btn btn-outline-secondary mb-3">← Back to @recipe.Category</a>

    <h1>@recipe.Title</h1>
    <span class="badge bg-secondary mb-3">@recipe.Category</span>

    <StarRating RecipeId="recipe.Id" @rendermode="InteractiveServer" />

    <h3 class="mt-4">Ingredients</h3>
    <ul>
        @foreach (var ingredient in recipe.Ingredients.Split(',', StringSplitOptions.TrimEntries))
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            var text = step.TrimStart();
            if (text.Length > 2 && text[1] == '.')
                text = text[3..];
            <li>@text</li>
        }
    </ol>
}

@code {
    [Parameter] public int Id { get; set; }

    private Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@page "/submit"
@using RecipeCommunity.Services
@using RecipeCommunity.Models

@attribute [RenderModeInteractiveServer]

@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe</PageTitle>

<h1>Submit a Recipe</h1>

@if (submitted)
{
    <div class="alert alert-success">
        <strong>Thank you!</strong> Your recipe has been submitted successfully.
        <a href="/recipe/@newRecipe.Id">View your recipe</a>
    </div>
}
else
{
    <EditForm Model="newRecipe" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="newRecipe.Title" />
            <ValidationMessage For="() => newRecipe.Title" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="newRecipe.Category">
                <option value="">-- Select a category --</option>
                <option value="Italian">Italian</option>
                <option value="Indian">Indian</option>
                <option value="Mexican">Mexican</option>
                <option value="Asian">Asian</option>
                <option value="Desserts">Desserts</option>
                <option value="Other">Other</option>
            </InputSelect>
            <ValidationMessage For="() => newRecipe.Category" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (comma-separated)</label>
            <InputTextArea id="ingredients" class="form-control" rows="4" @bind-Value="newRecipe.Ingredients" />
            <ValidationMessage For="() => newRecipe.Ingredients" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="newRecipe.Steps" />
            <ValidationMessage For="() => newRecipe.Steps" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

